const items = $input.all();
return items.map(item => {
  const nombre = item.json.customer_name || '';
  const msg = nombre && nombre !== 'Cliente'
    ? `\u00bfTodo bien, ${nombre}? Qued\u00e9 esperando tu respuesta \ud83d\ude0a \u00bfSegu\u00eds con la consulta?`
    : `\u00bfTodo bien? Qued\u00e9 esperando tu respuesta \ud83d\ude0a \u00bfSegu\u00eds con la consulta?`;
  return {
    from: item.json.phone_from,
    to: item.json.phone,
    phone: item.json.phone,
    type: 'text',
    text: { body: msg, preview_url: false }
  };
});

// ── 1. EXTRAER DATOS DEL MENSAJE YCLOUD ──────────────────────────
const body = $input.item.json.body;
const whatsappMsg = body.whatsappInboundMessage;

const messageId   = whatsappMsg.id;
const wamid       = whatsappMsg.wamid;
const from        = whatsappMsg.from;
const to          = whatsappMsg.to;
const customerName = whatsappMsg.customerProfile?.name || 'Cliente';
const messageType = whatsappMsg.type;
const messageBody = whatsappMsg.text?.body || '';
const timestamp   = whatsappMsg.sendTime;
const wabaId      = whatsappMsg.wabaId;
const eventType   = body.type;
const eventId     = body.id;

// ── 2. CALCULAR HORARIO DE ATENCIÓN (Argentina UTC-3) ────────────
// sendTime puede venir en ms (epoch) o como string ISO
const fecha = typeof timestamp === 'number'
  ? new Date(timestamp)
  : new Date(timestamp);

const offsetArg   = -3;
const horaArg     = new Date(fecha.getTime() + offsetArg * 60 * 60 * 1000);

const hora        = horaArg.getUTCHours();
const minutos     = horaArg.getUTCMinutes();
const dia         = horaArg.getUTCDay(); // 0 = domingo, 6 = sábado

const horaDecimal    = hora + minutos / 60;
const esDomingo      = dia === 0;
const dentroDeHorario = !esDomingo && horaDecimal >= 9 && horaDecimal < 18;

// ── 3. RETORNAR TODO JUNTO ────────────────────────────────────────
return {
  // Datos del mensaje
  messageId,
  wamid,
  from,
  to,
  customerName,
  messageType,
  messageBody,
  timestamp,
  wabaId,
  eventType,
  eventId,
  // Horario
  dentroDeHorario
};

// Preparar el payload para YCloud WhatsApp API
const phoneFrom =  $('Webhook1').first().json.body.whatsappInboundMessage.to;
const phoneTo = $('Webhook1').first().json.body.whatsappInboundMessage.from;
const messageText = $input.first().json.output;

return {
  from: phoneFrom,
  to: phoneTo,
  type: "text",
  text: {
    body: messageText,
    preview_url: true
  }
};

const items = $input.all();

// Agrupar por teléfono y quedarse con el más reciente
const porTelefono = {};
for (const item of items) {
  const phone = item.json.phone;
  if (!porTelefono[phone]) {
    porTelefono[phone] = item;
  } else {
    // Quedarse con el de last_bot_message_at más reciente
    const actual = new Date(porTelefono[phone].json.last_bot_message_at);
    const nuevo = new Date(item.json.last_bot_message_at);
    if (nuevo > actual) {
      porTelefono[phone] = item;
    }
  }
}

return Object.values(porTelefono);

